// W-10 Health Check Engine -- P-163 Antigravity Auto-Manutencao
const apiKey  = $env.N8N_API_KEY  || '';
const baseUrl = $env.N8N_BASE_URL || 'https://vanguard-vanguard-n8n.0ul9nk.easypanel.host';
const chatId  = $env.TELEGRAM_CHAT_ID || '8895733647';

// Workflows conhecidos (W-1 a W-9) que devem estar ativos
const EXPECTED_ACTIVE = ['W-1','W-2','W-3','W-4','W-5','W-6','W-7','W-8','W-9','W-10'];

let workflows = [];
let failedExecs = [];
let apiError = null;

// Buscar lista de workflows
try {
  const wfResp = await $helpers.httpRequest({
    method: 'GET',
    url: `${baseUrl}/api/v1/workflows?limit=250`,
    headers: { 'X-N8N-API-KEY': apiKey },
    returnFullResponse: false
  });
  workflows = (wfResp && wfResp.data) ? wfResp.data : [];
} catch(e) {
  apiError = `n8n API inacessivel: ${e.message}`;
}

// Buscar execucoes com erro (ultimas 50)
if (!apiError) {
  try {
    const execResp = await $helpers.httpRequest({
      method: 'GET',
      url: `${baseUrl}/api/v1/executions?status=error&limit=50&includeData=false`,
      headers: { 'X-N8N-API-KEY': apiKey },
      returnFullResponse: false
    });
    failedExecs = (execResp && execResp.data) ? execResp.data : [];
  } catch(e) {
    failedExecs = [];
  }
}

const now    = new Date();
const ontem  = new Date(now.getTime() - 24*60*60*1000);
const dataHora = now.toISOString().replace('T',' ').slice(0,16) + ' UTC';

// Erro critico: API inacessivel
if (apiError) {
  const texto = `🔴 W-10 CRITICO -- ${dataHora}\n\n${apiError}\n\n🤖 ANTIGRAVITY:\n  .\\scripts\\n8n_antigravity_repair.ps1\n  Skill: @systematic-debugging n8n API offline`;
  return [{ json: { textoOK: '', textoAlerta: texto, temAlerta: true, chatId, antigravityContext: apiError, dataHora } }];
}

// Mapa id->nome dos workflows
const wfMap = {};
workflows.forEach(function(w) { wfMap[w.id] = w.name; });

// Filtrar execucoes das ultimas 24h
const erros24h = failedExecs.filter(function(e) {
  const dt = new Date(e.startedAt || e.createdAt || 0);
  return dt >= ontem;
});

// Agrupar erros por workflow
const errorsByWf = {};
erros24h.forEach(function(e) {
  const nome = wfMap[e.workflowId] || ('ID:' + e.workflowId);
  if (!errorsByWf[nome]) errorsByWf[nome] = [];
  const msg = (e.data && e.data.resultData && e.data.resultData.error)
    ? (e.data.resultData.error.message || 'erro sem mensagem')
    : 'sem detalhes';
  errorsByWf[nome].push({ id: e.id, startedAt: e.startedAt, msg: msg.substring(0, 150) });
});

// Verificar workflows esperados inativos
const inactivos = [];
EXPECTED_ACTIVE.forEach(function(wName) {
  const found = workflows.find(function(w) { return w.name.includes(wName); });
  if (found && !found.active) {
    inactivos.push(found.name);
  }
});

const totalWf = workflows.length;
const ativosCount = workflows.filter(function(w) { return w.active; }).length;
const wfComErro = Object.keys(errorsByWf).length;
const temAlerta = wfComErro > 0 || inactivos.length > 0;

let textoOK = '';
let textoAlerta = '';
let antigravityContext = '';

if (!temAlerta) {
  textoOK = `✅ n8n SAUDAVEL -- ${dataHora}\n\n` +
    `Workflows: ${totalWf} total | ${ativosCount} ativos\n` +
    `Erros 24h: 0\n` +
    `Inativos inesperados: 0\n\n` +
    `Sistema operando normalmente. Proximo check: amanha 6h30 BRT.`;
} else {
  const linhas = ['🔴 n8n FALHA -- ' + dataHora, ''];

  if (wfComErro > 0) {
    linhas.push(`❌ Erros nas ultimas 24h (${wfComErro} workflow(s)):`);
    Object.entries(errorsByWf).forEach(function([nome, erros]) {
      linhas.push(`  • ${nome}: ${erros.length} falha(s)`);
      const ultimo = erros[0];
      if (ultimo.msg && ultimo.msg !== 'sem detalhes') {
        linhas.push(`    └ ${ultimo.msg}`);
      }
      linhas.push(`    └ ID execucao: ${ultimo.id}`);
    });
    linhas.push('');
  }

  if (inactivos.length > 0) {
    linhas.push(`⚠️ Workflows INATIVOS inesperados (${inactivos.length}):`);
    inactivos.forEach(function(n) { linhas.push(`  • ${n}`); });
    linhas.push('');
  }

  const workflowsDebug = Object.keys(errorsByWf).concat(inactivos).join(', ');
  antigravityContext = `Workflows com problema: ${workflowsDebug}. Data: ${dataHora}.`;

  linhas.push('🤖 ANTIGRAVITY -- Para diagnosticar:');
  linhas.push('  .\\scripts\\n8n_antigravity_repair.ps1');
  linhas.push('  Skill: @n8n-validation-expert -> @systematic-debugging');

  textoAlerta = linhas.join('\n');
}

return [{ json: { textoOK, textoAlerta, temAlerta, chatId, antigravityContext, wfComErro, inativosCount: inactivos.length, dataHora } }];

// Registrar falha no PENDING_REVIEW.md via GitHub API
const githubToken = $env.GITHUB_PAT_READONLY || '';
const repo        = 'subdiretormnmsgm-commits/vanguard';
const path        = 'PENTALATERAL_UNIVERSAL/INTELLIGENCE_HUB/PENDING_REVIEW.md';
const contexto    = $json.antigravityContext || 'Falha detectada pelo W-10';
const dataHora    = $json.dataHora || new Date().toISOString();

try {
  // Ler sha atual do arquivo
  const getResp = await $helpers.httpRequest({
    method: 'GET',
    url: `https://api.github.com/repos/${repo}/contents/${path}`,
    headers: { 'Authorization': `token ${githubToken}`, 'Accept': 'application/vnd.github.v3+json' },
    returnFullResponse: false,
    ignoreHttpStatusErrors: true
  });

  const sha = (getResp && getResp.sha) ? getResp.sha : null;
  const existingContent = (getResp && getResp.content)
    ? Buffer.from(getResp.content.replace(/\n/g,''), 'base64').toString('utf8')
    : '';

  const entrada = `\n## W-10 ALERTA -- ${dataHora}\n**Contexto:** ${contexto}\n**Skill recomendada:** @n8n-validation-expert -> @systematic-debugging\n**Status:** PENDENTE REVISAO\n\n`;
  const novoConteudo = existingContent + entrada;
  const novoBase64   = Buffer.from(novoConteudo).toString('base64');

  const body = { message: `chore(w10): alerta n8n health check ${dataHora}`, content: novoBase64 };
  if (sha) body.sha = sha;

  await $helpers.httpRequest({
    method: 'PUT',
    url: `https://api.github.com/repos/${repo}/contents/${path}`,
    headers: { 'Authorization': `token ${githubToken}`, 'Accept': 'application/vnd.github.v3+json' },
    body: JSON.stringify(body),
    returnFullResponse: false,
    ignoreHttpStatusErrors: true
  });

  return [{ json: { ...$json, githubPushOk: true } }];
} catch(e) {
  return [{ json: { ...$json, githubPushOk: false, githubError: e.message } }];
}
